import "container/heap"

type IntHeap []int

func (h IntHeap) Len() int { return len(h) }

func (h IntHeap) Less(i, j int) bool { return h[i] < h[j] }

func (h IntHeap) Swap(i, j int) { h[i], h[j] = h[j], h[i] }

func (h *IntHeap) Push(x interface{}) { *h = append(*h, x.(int)) }

func (h *IntHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

type State struct {
	totalCost int64
	time      int64
	i         int64
	j         int64
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	// Directions: right (0, 1), down (1, 0)
	directions := [2][2]int64{{0, 1}, {1, 0}}

	// Priority queue: (total_cost, time, i, j)
	pq := &IntHeap{}
	heap.Init(pq)
	// Visited structure to keep track of the minimum cost to reach each cell at a certain time
	visited := make([][]int64, m)
	for i := range visited {
		visited[i] = make([]int64, n)
	}
	visited[0][0] = 1 // Starting at (0, 0) with cost 1

	// Push initial state into the priority queue
	heap.Push(pq, 1)

	// Use a priority queue to track states
	pqStates := make([]State, 0)
	pqStates = append(pqStates, State{totalCost: 1, time: 0, i: 0, j: 0})

	for len(pqStates) > 0 {
		state := pqStates[0]
		heap.Pop(pq)
		cost, time, i, j := state.totalCost, state.time, state.i, state.j

		// If we reach the destination
		if i == m-1 && j == n-1 {
			return cost
		}

		// If current cost is higher than the recorded minimum, skip
		if cost > visited[i][j] {
			continue
		}

		// Determine the current time step (odd or even)
		if time%2 == 0 {
			// Even time: must wait
			// Wait cost is added, and time increases by 1
			newTime := time + 1
			newCost := cost + int64(waitCost[i][j])
			if newCost < visited[i][j] {
				visited[i][j] = newCost
				pqStates = append(pqStates, State{totalCost: newCost, time: newTime, i: i, j: j})
			}
		} else {
			// Odd time: must move right or down
			for _, dir := range directions {
			 ni, nj := i+dir[0], j+dir[1]
			 if ni >= 0 && ni < m && nj >= 0 && nj < n {
				 entryCost := (ni + 1) * (nj + 1)
				 newTime := time + 1
				 newCost := cost + entryCost
				 if newCost < visited[ni][nj] {
					 visited[ni][nj] = newCost
					 pqStates = append(pqStates, State{totalCost: newCost, time: newTime, i: ni, j: nj})
				 }
			 }
			}
		}
	}

	// If no path found (should not happen as grid is connected)
	return -1
}
